// // When y is not between 112 and 368 or is not a multiple of 51, set RGB to white
module top_module(input[9:0] x, y, output reg[2:0] rgb);always@(*) begin
		if(y <= 368 && y >= 112 && ((y - 112) % 51 == 0))
			rgb <= 3'b111;
		else if (y < 368 && y > 112 && (x % 51 == 0))
			rgb <= 3'b111;
		else rgb <= 3'b000;
	end
endmodule
